SCHEMA = {
    "name": "poison_lethal_check",
    "description": "Calculates exactly how much damage current poison will deal over the next N turns, and whether it is lethal.",
    "input_schema": {
        "type": "object",
        "properties": {
            "current_poison": {"type": "integer"},
            "enemy_hp": {"type": "integer"},
            "turns": {"type": "integer", "description": "Number of turns to project. Use a large number (e.g. 10) for total lethal check."}
        },
        "required": ["current_poison", "enemy_hp", "turns"]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(current_poison, enemy_hp, turns):
    total_damage = 0
    poison = current_poison
    turns_to_lethal = None

    for t in range(1, turns + 1):
        if poison <= 0:
            break
        total_damage += poison
        if total_damage >= enemy_hp and turns_to_lethal is None:
            turns_to_lethal = t
        poison -= 1

    return {
        "damage_over_turns": total_damage,
        "is_lethal_within_turns": turns_to_lethal is not None,
        "turns_to_lethal": turns_to_lethal,
        "remaining_hp_after_turns": max(0, enemy_hp - total_damage)
    }

TEST_CASES = [
    {
        "inputs": {"current_poison": 10, "enemy_hp": 25, "turns": 3},
        "expected": {"damage_over_turns": 27, "is_lethal_within_turns": True, "turns_to_lethal": 3, "remaining_hp_after_turns": 0}
    },
    {
        "inputs": {"current_poison": 5, "enemy_hp": 30, "turns": 5},
