import math

SCHEMA = {
    "name": "poison_lethal_calc",
    "description": "Calculates the exact number of turns until an enemy dies to its current poison stacks, helping you decide whether to stop attacking and only play block.",
    "input_schema": {
        "type": "object",
        "properties": {
            "enemy_hp": {"type": "integer"},
            "poison_stacks": {"type": "integer"}
        },
        "required": ["enemy_hp", "poison_stacks"]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(enemy_hp, poison_stacks):
    if not poison_stacks or poison_stacks <= 0:
        return {"dies_to_poison": False, "turns_to_die": -1, "total_poison_damage": 0}

    total_dmg = 0
    turns = 0
    current_poison = poison_stacks

    while current_poison > 0:
        turns += 1
        total_dmg += current_poison
        if total_dmg >= enemy_hp:
            return {
                "dies_to_poison": True,
                "turns_to_die": turns,
                "total_poison_damage": total_dmg
            }
        current_poison -= 1

    return {
        "dies_to_poison": False,
        "turns_to_die": -1,
        "total_poison_damage": total_dmg
    }

