    {
        "inputs": {"enemy_hp": 10, "poison_stacks": 4},
        "expected": {"dies_to_poison": True, "turns_to_die": 3, "total_poison_damage": 10}
    },
    {
        "inputs": {"enemy_hp": 20, "poison_stacks": 5},
